class FenwickTree {
    private size: number;
    private tree: number[];

    constructor(size: number) {
        this.size = size;
        this.tree = new Array(size + 1).fill(0);
    }

    update(index: number, delta: number): void {
        index += 1; // 1-based index
        while (index <= this.size) {
            this.tree[index] += delta;
            index += index & -index;
        }
    }

    query(index: number): number {
        index += 1; // 1-based index
        let res = 0;
        while (index > 0) {
            res += this.tree[index];
            index -= index & -index;
        }
        return res;
    }

    rangeQuery(l: number, r: number): number {
        if (l > r) return 0;
        return this.query(r) - this.query(l - 1);
    }
}

function solve(nums: number[], queries: number[][]): number[] {
    const n = nums.length;
    const bit0 = new FenwickTree(n);
    const bit1 = new FenwickTree(n);
    const bit2 = new FenwickTree(n);
    const bit3 = new FenwickTree(n);

    const depths: number[] = new Array(n);
    for (let i = 0; i < n; i++) {
        depths[i] = getDepth(nums[i]);
    }

    for (let i = 0; i < n; i++) {
        const depth = depths[i];
        if (depth === 0) {
            bit0.update(i, 1);
        } else if (depth === 1) {
            bit1.update(i, 1);
        } else if (depth === 2) {
            bit2.update(i, 1);
        } else if (depth === 3) {
            bit3.update(i, 1);
        }
    }

    const answer: number[] = [];

    function getDepth(x: number): number {
        let depth = 0;
        let current = x;
        while (current !== 1) {
            current = countSetBits(current);
            depth++;
        }
        return depth;
    }

    function countSetBits(x: number): number {
        return x.toString(2).split('1').length - 1;
    }

    for (const query of queries) {
        if (query[0] === 1) {
            const [_, l, r, k] = query;
            if (k < 0 || k > 3) {
                answer.push(0);
                continue;
            }
            let bit: FenwickTree;
            if (k === 0) {
                bit = bit0;
            } else if (k === 1) {
                bit = bit1;
            } else if (k === 2) {
                bit = bit2;
            } else {
                bit = bit3;
            }
            const count = bit.rangeQuery(l, r);
            answer.push(count);
        } else {
            const [_, idx, val] = query;
            const old_depth = depths[idx];
            if (old_depth === 0) {
                bit0.update(idx, -1);
            } else if (old_depth === 1) {
                bit1.update(idx, -1);
            } else if (old_depth === 2) {
                bit2.update(idx, -1);
            } else {
                bit3.update(idx, -1);
            }
            const new_depth = getDepth(val);
            if (new_depth === 0) {
                bit0.update(idx, 1);
            } else if (new_depth === 1) {
                bit1.update(idx, 1);
            } else if (new_depth === 2) {
                bit2.update(idx, 1);
            } else {
                bit3.update(idx, 1);
            }
            nums[idx] = val;
            depths[idx] = new_depth;
        }
    }
    return answer;
}

