class FenwickTree {
    private val size: Int
    private val tree: MutableList<Int>

    constructor(size: Int) {
        this.size = size
        this.tree = MutableList(size + 1) { 0 }
    }

    fun update(index: Int, delta: Int) {
        var i = index + 1 // 1-based index
        while (i <= size) {
            tree[i] += delta
            i += i and -i
        }
    }

    fun query(index: Int): Int {
        var i = index + 1
        var res = 0
        while (i > 0) {
            res += tree[i]
            i -= i and -i
        }
        return res
    }

    fun rangeQuery(l: Int, r: Int): Int {
        if (l > r) return 0
        return query(r) - query(l - 1)
    }
}

fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val n = nums.size
    val ft = Array(6) { FenwickTree(n) }

    val depths = Array(n) { 0 }

    for (i in 0 until n) {
        depths[i] = getDepth(nums[i])
    }

    for (i in 0 until n) {
        val d = depths[i]
        if (d in 0..5) {
            ft[d].update(i, 1)
        }
    }

    val answer = mutableListOf<Long>()

    for (query in queries) {
        when (query[0]) {
            1L -> {
                val l = query[1].toInt()
                val r = query[2].toInt()
                val k = query[3].toInt()
                if (k < 0 || k > 5) {
                    answer.add(0L)
                    continue
                }
                val idx = k
                if (idx < 0 || idx > 5) {
                    answer.add(0L)
                    continue
                }
                val count = ft[idx].rangeQuery(l, r)
                answer.add(count.toLong())
            }
            2L -> {
                val idx = query[1].toInt()
                val val = query[2].toLong()
                val oldD = depths[idx]
                if (oldD in 0..5) {
                    ft[oldD].update(idx, -1)
                }
                val newD = getDepth(val)
                if (newD in 0..5) {
                    ft[newD].update(idx, 1)
                }
                nums[idx] = val
                depths[idx] = newD
            }
            else -> {
                // invalid query, but according to problem statement, it's not possible
                answer.add(0L)
            }
        }
    }

    return answer.toLongArray()
}

fun getDepth(x: Long): Int {
    var depth = 0
    var current = x
    while (current != 1L) {
        current = current.bitCount().toLong()
        depth++
    }
    return depth
}
